import dspy
from dspy.evaluate import Evaluate

class ConsistencyChecker(Evaluate):
    def __init__(self, metric=dspy.evaluate.answer_exact_match, num_runs=10):
        super().__init__(metric=metric)
        self.num_runs = num_runs

    def evaluate(self, example, pred, trace=None):
        outputs = []
        module = self.config.get('module')

        for _ in range(self.num_runs):
            with dspy.context()
                pred = module.forward(example)
                outputs.append(pred.completions[0])

        variance = len(set(outputs)) / len(outputs)
        return {'consistency_score': 1 - variance}

