import dspy

class ConstrainedAnswer(dspy.Signature):
    question: str = dspy.InputField()
    answer: str = dspy.OutputField(desc="Answer in JSON format: {'result': str, 'confidence': float}")
    format_check: bool = dspy.OutputField()

class FormatConstrainedAgent(dspy.Module):
    def __init__(self):
        super().__init__()
        self.generate = dspy.ChainOfThought(ConstrainedAnswer)

    def forward(self, question):
        pred = self.generate(question=question)
        # Auto-validate format
        return pred if pred.format_check else self.retry(question)

    def retry(self, question):
        return self.generate(question=question, n=3)

import dspy
from collections import Counter

class EnsemblePredictor(dspy.Module):
    def __init__(self, base_module, n_predictors=3):
        super().__init__()
        self.predictors = [base_module.copy() for _ in range(n_predictors)]

    def forward(self, *args, **kwargs):
        predictions = []
        for predictor in self.predictors:
            pred = predictor.forward(*args, **kwargs)
            predictions.append(pred.answer)

        # Majority vote
        vote = Counter(predictions).most_common(1)[0]
        return dspy.Prediction(answer=vote[0], confidence=vote[1]/len(predictions))

